def _starburst_dataset_column_to_nested(
    starburst_dataset_column: StarburstDatasetColumn,
) -> StarburstDatasetColumnNested:
    """Convert flat StarburstDatasetColumn to nested format."""
    attrs = StarburstDatasetColumnAttributes()
    _populate_starburst_dataset_column_attrs(attrs, starburst_dataset_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        starburst_dataset_column,
        _STARBURST_DATASET_COLUMN_REL_FIELDS,
        StarburstDatasetColumnRelationshipAttributes,
    )
    return StarburstDatasetColumnNested(
        guid=starburst_dataset_column.guid,
        type_name=starburst_dataset_column.type_name,
        status=starburst_dataset_column.status,
        version=starburst_dataset_column.version,
        create_time=starburst_dataset_column.create_time,
        update_time=starburst_dataset_column.update_time,
        created_by=starburst_dataset_column.created_by,
        updated_by=starburst_dataset_column.updated_by,
        classifications=starburst_dataset_column.classifications,
        classification_names=starburst_dataset_column.classification_names,
        meanings=starburst_dataset_column.meanings,
        labels=starburst_dataset_column.labels,
        business_attributes=starburst_dataset_column.business_attributes,
        custom_attributes=starburst_dataset_column.custom_attributes,
        pending_tasks=starburst_dataset_column.pending_tasks,
        proxy=starburst_dataset_column.proxy,
        is_incomplete=starburst_dataset_column.is_incomplete,
        provenance_type=starburst_dataset_column.provenance_type,
        home_id=starburst_dataset_column.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _starburst_dataset_column_from_nested(
    nested: StarburstDatasetColumnNested,
) -> StarburstDatasetColumn:
    """Convert nested format to flat StarburstDatasetColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else StarburstDatasetColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _STARBURST_DATASET_COLUMN_REL_FIELDS,
        StarburstDatasetColumnRelationshipAttributes,
    )
    return StarburstDatasetColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_starburst_dataset_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _starburst_dataset_column_to_nested_bytes(
    starburst_dataset_column: StarburstDatasetColumn, serde: Serde
) -> bytes:
    """Convert flat StarburstDatasetColumn to nested JSON bytes."""
    return serde.encode(_starburst_dataset_column_to_nested(starburst_dataset_column))


def _starburst_dataset_column_from_nested_bytes(
    data: bytes, serde: Serde
) -> StarburstDatasetColumn:
    """Convert nested JSON bytes to flat StarburstDatasetColumn."""
    nested = serde.decode(data, StarburstDatasetColumnNested)
    return _starburst_dataset_column_from_nested(nested)


